export interface ResearchFormData {
  name: string;
  geography?: string;
  facts?: string;
}

import { GoogleGenAI, Type } from "@google/genai";
import { ResearchFormData, ResearchReport } from "../types";

export const generateResearchReport = async (data: ResearchFormData): Promise<ResearchReport> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const systemPrompt = `You are a world-class onomastics expert and professional genealogist. 
Your task is to provide a deep research report on a given name or surname.

Follow this Research Protocol strictly:
1. Etymology: Analyze the linguistic root. Is it patronymic, professional, topographic, or a nickname? Check for roots in relevant language groups.
2. Geographic Distribution: Identify historical "hubs" of this surname prior to the 20th century using census data and regional records.
3. Social Analysis: Determine which social classes or groups typically held this name in the specified region.
4. Variability: Check for phonetic distortions and common spelling variations in historical registers.
5. Archives: List specific archives (e.g., National Archives, church records) and document types for further verification.

Output the result in a structured format.`;

  const userPrompt = `
Context:
Name(s): ${data.name}
Geography: ${data.geography || "Unknown"}.
Known Facts: ${data.facts || "No additional facts provided."}.

Research Protocol:
Etymology: Analyze the linguistic root. Is it patronymic, professional, topographic, or a nickname? Check for roots in relevant language groups.
Geographic Distribution: Identify historical "hubs" of this surname prior to the 20th century using census data and regional records.
Social Analysis: Determine which social classes or groups typically held this name in the specified region.
Variability: Check for phonetic distortions and common spelling variations in historical registers.
Output: A structured report including a list of specific archives (e.g., National Archives, church records) and document types for further verification.
  `;

  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: userPrompt,
    config: {
      systemInstruction: systemPrompt,
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          etymology: { type: Type.STRING },
          geographicDistribution: { type: Type.STRING },
          socialAnalysis: { type: Type.STRING },
          variability: { type: Type.STRING },
          archives: { 
            type: Type.ARRAY, 
            items: { type: Type.STRING } 
          }
        },
        required: ["etymology", "geographicDistribution", "socialAnalysis", "variability", "archives"]
      }
    },
  });

  const reportJson = JSON.parse(response.text || "{}");

  return {
    name: data.name,
    geography: data.geography || "Unknown",
    facts: data.facts || "None",
    ...reportJson
  };
};

export const generateNameIllustration = async (name: string, description: string): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const prompt = `A highly detailed historical illustration related to the surname/name '${name}'. 
The scene should reflect its origins or meaning: ${description.substring(0, 200)}. 
Style: Elegant, atmospheric oil painting or classic archival ink sketch. No text in image. 
Professional quality, archival aesthetic.`;

  const response = await ai.models.generateContent({
    model: 'gemini-2.5-flash-image',
    contents: { parts: [{ text: prompt }] },
    config: {
      imageConfig: {
        aspectRatio: "16:9"
      }
    }
  });

  for (const part of response.candidates[0].content.parts) {
    if (part.inlineData) {
      return `data:image/png;base64,${part.inlineData.data}`;
    }
  }

  throw new Error("Failed to generate image");
};

import React, { useState } from 'react';
import { ResearchFormData } from '../types';

interface Props {
  onSubmit: (data: ResearchFormData) => void;
  isLoading: boolean;
}

const ResearchForm: React.FC<Props> = ({ onSubmit, isLoading }) => {
  const [formData, setFormData] = useState<ResearchFormData>({
    name: '',
    geography: '',
    facts: ''
  });

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!formData.name.trim()) return;
    onSubmit(formData);
  };

  return (
    <form onSubmit={handleSubmit} className="space-y-6">
      <div>
        <label className="block text-sm font-semibold text-stone-700 mb-1">
          Name / Surname <span className="text-red-500">*</span>
        </label>
        <input
          type="text"
          required
          placeholder="e.g. Montgomery, Schmidt, Smith"
          className="w-full px-4 py-3 rounded-lg border border-stone-300 focus:ring-2 focus:ring-amber-600 focus:border-transparent outline-none transition-all bg-white/80"
          value={formData.name}
          onChange={(e) => setFormData({ ...formData, name: e.target.value })}
        />
      </div>

      <div>
        <label className="block text-sm font-semibold text-stone-700 mb-1">
          Geography (Region/Country)
        </label>
        <input
          type="text"
          placeholder="e.g. Yorkshire, England or Unknown"
          className="w-full px-4 py-3 rounded-lg border border-stone-300 focus:ring-2 focus:ring-amber-600 focus:border-transparent outline-none transition-all bg-white/80"
          value={formData.geography}
          onChange={(e) => setFormData({ ...formData, geography: e.target.value })}
        />
      </div>

      <div>
        <label className="block text-sm font-semibold text-stone-700 mb-1">
          Known Facts or Family Legends
        </label>
        <textarea
          rows={4}
          placeholder="Migration history, social status, specific oral traditions..."
          className="w-full px-4 py-3 rounded-lg border border-stone-300 focus:ring-2 focus:ring-amber-600 focus:border-transparent outline-none transition-all bg-white/80"
          value={formData.facts}
          onChange={(e) => setFormData({ ...formData, facts: e.target.value })}
        />
      </div>

      <button
        type="submit"
        disabled={isLoading}
        className={`w-full py-4 px-6 rounded-lg text-white font-bold text-lg transition-all transform hover:scale-[1.01] active:scale-[0.99] ${
          isLoading 
            ? 'bg-stone-400 cursor-not-allowed' 
            : 'bg-amber-800 hover:bg-amber-900 shadow-lg'
        }`}
      >
        {isLoading ? (
          <span className="flex items-center justify-center">
            <svg className="animate-spin -ml-1 mr-3 h-5 w-5 text-white" fill="none" viewBox="0 0 24 24">
              <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
