import React, { useState } from 'react';
import { ResearchFormData, ResearchReport } from './types';
import { generateResearchReport, generateNameIllustration } from './services/geminiService';
import ResearchForm from './components/ResearchForm';
import ReportDisplay from './components/ReportDisplay';

const App: React.FC = () => {
  const [report, setReport] = useState<ResearchReport | null>(null);
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const handleResearch = async (data: ResearchFormData) => {
    setIsLoading(true);
    setError(null);
    setReport(null);

    try {
      // Step 1: Generate the Text Report
      const textReport = await generateResearchReport(data);

      // Update state with text first for immediate feedback
      setReport({ ...textReport });

      // Step 2: Generate the Illustration in the background
      try {
        const imageUrl = await generateNameIllustration(data.name, textReport.etymology);
        setReport(prev => prev ? { ...prev, imageUrl } : null);
      } catch (imgErr) {
        console.error("Image generation failed", imgErr);
        // Continue without image
      }
    } catch (err: any) {
      console.error(err);
      setError(err.message || "An unexpected error occurred while accessing the archives.");
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="min-h-screen pb-20 selection:bg-amber-100 selection:text-amber-900">
      {/* Navigation / Header */}
      <header className="bg-stone-900 text-stone-100 py-12 px-4 shadow-xl">
        <div className="max-w-6xl mx-auto flex flex-col items-center text-center">
          <div className="mb-4">
            <svg className="w-16 h-16 text-amber-600 mb-2 mx-auto" fill="currentColor" viewBox="0 0 24 24">
              <path d="M12 2C6.48 2 2 6.48 2 12s4.48 10 10 10 10-4.48 10-10S17.52 2 12 2zm1 15h-2v-6h2v6zm0-8h-2V7h2v2z" />
            </svg>
          </div>
          <h1 className="serif text-5xl md:text-6xl font-bold mb-4 tracking-tight">Onomastica Research Lab</h1>
          <p className="max-w-2xl text-stone-400 text-lg font-light leading-relaxed">
            Uncover the deep linguistic roots, geographic history, and social narratives encoded within your name.
          </p>
        </div>
      </header>

      <main className="max-w-6xl mx-auto px-4 -mt-8">
        {!report && !isLoading && (
          <div className="max-w-2xl mx-auto bg-white rounded-2xl shadow-2xl p-8 md:p-12 border border-stone-100">
            <div className="mb-8 text-center">
              <h2 className="serif text-3xl font-bold text-stone-800 mb-2">Initialize Dossier</h2>
              <p className="text-stone-500">Provide the following context for our research protocols.</p>
            </div>
            <ResearchForm onSubmit={handleResearch} isLoading={isLoading} />
          </div>
        )}

        {isLoading && !report && (
          <div className="max-w-2xl mx-auto text-center py-20 space-y-6">
            <div className="relative w-32 h-32 mx-auto">
              <div className="absolute inset-0 rounded-full border-4 border-amber-200 border-t-amber-800 animate-spin"></div>
              <div className="absolute inset-4 rounded-full border-2 border-amber-600/30 border-b-amber-600/60 animate-spin duration-[3s]"></div>
            </div>
            <div className="space-y-3">
              <h3 className="serif text-2xl font-bold text-stone-800">Scouring Historical Registers...</h3>
              <p className="text-stone-500 animate-pulse">Cross-referencing parish records, census hubs, and etymological databases.</p>
            </div>
          </div>
        )}

        {error && (
          <div className="max-w-2xl mx-auto mt-8 p-4 bg-red-50 border border-red-200 text-red-700 rounded-lg text-center">
            <p className="font-semibold">Research Interrupted</p>
            <p className="text-sm">{error}</p>
            <button 
              onClick={() => setError(null)}
              className="mt-4 text-sm underline hover:text-red-900"
            >
              Try again
            </button>
          </div>
        )}

        {report && (
          <div>
            <ReportDisplay report={report} />
            <div className="mt-12 text-center">
              <button 
                onClick={() => setReport(null)}
                className="text-stone-500 hover:text-amber-800 font-medium transition-colors"
              >
                ← Start New Research
              </button>
            </div>
          </div>
        )}
      </main>

      {/* Sticky Bottom Branding */}
      <footer className="fixed bottom-4 right-4 z-50">
        <div className="bg-white/80 backdrop-blur shadow-lg border border-stone-200 rounded-full px-4 py-2 flex items-center space-x-2 text-xs font-semibold text-stone-600">
          <span className="w-2 h-2 bg-green-500 rounded-full animate-pulse"></span>
          <span>Archival Systems Active</span>
        </div>
      </footer>
    </div>
  );
};

