    );
    return (
      <div className="mt-6 rounded-xl overflow-hidden border-2 border-stone-200 shadow-md transition-all hover:shadow-lg print:shadow-none print:border print:border-stone-300">
        <img crossOrigin="anonymous" src={url} alt={label} className="w-full h-auto object-cover max-h-[400px]" />
      </div>
    );
  };

  return (
    <div id="research-report-container" className="max-w-5xl mx-auto py-10 print:py-0 print:m-0 print:max-w-none">
      {/* Wrapper to target for screenshot, ensuring it has correct styles when captured */}
      <div id="research-report" className="animate-fade-in space-y-10 p-4 md:p-8 bg-[#f8f5f2]">

        {/* Print-specific Styles */}
        <style>{`
          @media print {
            @page {
              size: A4;
              margin: 15mm;
            }
            body { 
              background: white !important; 
              color: black !important;
              font-size: 11pt !important;
            }
            .no-print { display: none !important; }
            .print-full-width { width: 100% !important; max-width: none !important; margin: 0 !important; padding: 0 !important; }
            .print-break-inside-avoid { break-inside: avoid; }
            .bg-parchment { background: #fffaf5 !important; border: 1px solid #e2e2e2 !important; box-shadow: none !important; }
            .bg-stone-50 { background: white !important; }
            header, footer, .sticky, button { display: none !important; }
            .serif { font-family: 'Crimson Pro', serif !important; }
            img { max-height: 4in !important; object-fit: contain !important; margin: 0 auto; display: block; }
          }
        `}</style>

        {/* Official Archive Header */}
        <div className="flex justify-between items-center border-b-2 border-stone-800 pb-4 mb-8">
          <div className="text-left">
            <p className="font-bold uppercase tracking-widest text-xs text-stone-800">Onomastica Research Lab</p>
            <p className="text-[10px] text-stone-500 italic">Historical & Genealogical Research Division</p>
          </div>
          <div className="text-right">
            <p className="text-[10px] text-stone-500 uppercase tracking-tighter">Record ID: {Math.floor(Date.now() / 1000).toString().slice(-6)}</p>
            <p className="text-[10px] text-stone-500">Date: {new Date().toLocaleDateString()}</p>
          </div>
        </div>

        {/* Header */}
        <div className="text-center space-y-3 border-b-2 border-amber-800/10 pb-8">
          <h2 className="serif text-5xl md:text-6xl font-bold text-stone-900 leading-tight">Historical Dossier: {report.name}</h2>
          <p className="text-amber-900/70 italic text-2xl font-light">Research Subject Origin: {report.geography}</p>
        </div>

        {/* Main Header Illustration */}
        {report.headerImageUrl && (
          <div className="relative overflow-hidden rounded-2xl shadow-2xl border-4 border-stone-200">
            <img 
              crossOrigin="anonymous"
              src={report.headerImageUrl} 
              alt={`Archetypal view of ${report.name}`}
              className="w-full h-auto"
            />
            <div className="absolute bottom-0 left-0 right-0 bg-stone-900/70 backdrop-blur-md p-4 text-white text-sm italic">
              Archetypal Lineage Visualization: {report.name}
            </div>
          </div>
        )}

        {/* Detailed Research Sections */}
        <div className="grid grid-cols-1 md:grid-cols-2 gap-10">
          <section className="bg-parchment p-8 rounded-2xl shadow-sm border border-stone-200 break-inside-avoid">
            <h3 className="serif text-3xl font-bold text-amber-900 mb-5 border-b-2 border-amber-800/10 pb-2">I. Etymology</h3>
            <p className="text-stone-800 leading-relaxed text-lg whitespace-pre-wrap mb-6">{report.etymology}</p>
            <SectionImage url={report.etymologyImageUrl} label="Etymological Context" />
          </section>

          <section className="bg-parchment p-8 rounded-2xl shadow-sm border border-stone-200 break-inside-avoid">
            <h3 className="serif text-3xl font-bold text-amber-900 mb-5 border-b-2 border-amber-800/10 pb-2">II. Geographic Distribution</h3>
            <p className="text-stone-800 leading-relaxed text-lg whitespace-pre-wrap mb-6">{report.geographicDistribution}</p>
            <SectionImage url={report.geoImageUrl} label="Historical Distribution" />
          </section>

          <section className="bg-parchment p-8 rounded-2xl shadow-sm border border-stone-200 break-inside-avoid">
            <h3 className="serif text-3xl font-bold text-amber-900 mb-5 border-b-2 border-amber-800/10 pb-2">III. Social Analysis</h3>
            <p className="text-stone-800 leading-relaxed text-lg whitespace-pre-wrap mb-6">{report.socialAnalysis}</p>
            <SectionImage url={report.socialImageUrl} label="Social Analysis" />
          </section>

          <section className="bg-parchment p-8 rounded-2xl shadow-sm border border-stone-200 break-inside-avoid">
            <h3 className="serif text-3xl font-bold text-amber-900 mb-5 border-b-2 border-amber-800/10 pb-2">IV. Variability</h3>
            <p className="text-stone-800 leading-relaxed text-lg whitespace-pre-wrap mb-6">{report.variability}</p>
            <SectionImage url={report.variabilityImageUrl} label="Phonetic Variability" />
          </section>
        </div>

        {/* Archives */}
        <section className="bg-stone-900 text-stone-100 p-10 rounded-2xl border-2 border-stone-800">
          <h3 className="serif text-3xl font-bold mb-6 text-amber-500">V. Primary Source Repositories</h3>
          <ul className="grid grid-cols-1 lg:grid-cols-2 gap-6">
            {report.archives.map((archive, index) => (
              <li key={index} className="flex items-start space-x-4">
                <span className="text-amber-500 font-bold text-xl">◈</span>
                <span className="text-lg opacity-90">{archive}</span>
              </li>
            ))}
          </ul>
        </section>
      </div>

      {/* Download Action - Sticky or static at bottom */}
      <div className="no-print flex flex-col items-center space-y-4 mt-12 py-8 border-t border-stone-200 bg-stone-50 rounded-b-2xl">
        <button 
          onClick={handleDownload}
          disabled={isCapturing}
          className={`group flex items-center space-x-4 px-10 py-5 text-white rounded-2xl font-bold text-xl transition-all transform hover:-translate-y-1 shadow-2xl outline-none ${
            isCapturing ? 'bg-stone-500 cursor-not-allowed' : 'bg-stone-900 hover:bg-black ring-offset-2 ring-amber-600 focus:ring-4'
          }`}
        >
          {isCapturing ? (
            <svg className="animate-spin h-6 w-6 text-white" fill="none" viewBox="0 0 24 24">
              <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
              <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
            </svg>
          ) : (
            <svg className="w-8 h-8 text-amber-500 group-hover:scale-110 transition-transform" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 16l4.586-4.586a2 2 0 012.828 0L16 16m-2-2l1.586-1.586a2 2 0 012.828 0L20 14m-6-6h.01M6 20h12a2 2 0 002-2V6a2 2 0 00-2-2H6a2 2 0 00-2 2v12a2 2 0 002 2z" />
            </svg>
          )}
          <span>{isCapturing ? 'Processing Screenshot...' : 'Save Research as Image (PNG)'}</span>
        </button>
        <p className="text-stone-500 text-sm font-medium">Captures the entire high-fidelity report for your records.</p>
      </div>
    </div>
  );
};

export default ReportDisplay;
